392	// RunQuorumWith invokes multiple harnesses concurrently and returns each
393	// result. Production callers should use RunQuorumViaService; tests may pass
394	// Runner.Run.
395	func RunQuorumWith(run RunFunc, opts QuorumOptions) ([]*Result, error) {
396		if len(opts.Harnesses) == 0 {
397			return nil, fmt.Errorf("agent: quorum requires at least one harness")
398		}
399	
400		threshold := effectiveThreshold(opts.Strategy, opts.Threshold, len(opts.Harnesses))
401		if threshold < 1 || threshold > len(opts.Harnesses) {
402			return nil, fmt.Errorf("agent: invalid quorum threshold %d for %d harnesses", threshold, len(opts.Harnesses))
403		}
404	
405		results := make([]*Result, len(opts.Harnesses))
406		var wg sync.WaitGroup
407		var mu sync.Mutex
408		var firstErr error
409	
410		for i, name := range opts.Harnesses {
411			wg.Add(1)
412			go func(idx int, harness string) {
413				defer wg.Done()
414				runOpts := opts.RunOptions
415				runOpts.Harness = harness
416				result, err := run(runOpts)
417				mu.Lock()
418				if err != nil && firstErr == nil {
419					firstErr = err
420				}
421				results[idx] = result
422				mu.Unlock()
423			}(i, name)
424		}
425		wg.Wait()
426	
427		return results, firstErr
428	}
