446	// QuorumMet returns true if enough results succeeded.
447	func QuorumMet(strategy string, threshold int, results []*Result) bool {
448		total := len(results)
449		eff := effectiveThreshold(strategy, threshold, total)
450		successes := 0
451		for _, r := range results {
452			if r != nil && r.ExitCode == 0 {
453				successes++
454			}
455		}
456		return successes >= eff
457	}
