459	func effectiveThreshold(strategy string, threshold, total int) int {
460		switch strategy {
461		case "any":
462			return 1
463		case "majority":
464			return (total / 2) + 1
465		case "unanimous":
466			return total
467		default:
468			if threshold > 0 {
469				return threshold
470			}
471			return 1
472		}
473	}
