475	// CondenseOutput filters raw agent output to keep only progress-relevant lines.
476	// The canonical implementation lives in agent/internal/comparison.CondenseOutput.
477	func CondenseOutput(input, namespacePrefix string) string {
478		var kept []string
479		skippingTokens := false
480		skippingDiff := false
481		blankRun := 0
482		lastWasKept := false
483		keepNextResult := false
484	
485		lines := strings.Split(input, "\n")
486		if len(lines) > 0 && lines[len(lines)-1] == "" {
487			lines = lines[:len(lines)-1]
488		}
489	
490		for _, line := range lines {
491			if strings.HasPrefix(line, "Commands run:") {
492				continue
493			}
494			if line == "tokens used" {
495				skippingTokens = true
496				continue
497			}
498			if skippingTokens {
499				skippingTokens = false
500				continue
501			}
502			if condenseIsDiffHeader(line) {
503				skippingDiff = true
504				continue
505			}
506			if skippingDiff {
507				if condenseIsDiffHeader(line) {
508					continue
509				}
510				if len(line) > 0 && (line[0] == '+' || line[0] == '-' || line[0] == ' ') {
511					continue
512				}
513				skippingDiff = false
514			}
515			if line == "" {
516				blankRun++
517				continue
518			}
519			keep := false
520			if keepNextResult {
521				keep = true
522				keepNextResult = false
523			}
524			if namespacePrefix != "" && strings.HasPrefix(line, namespacePrefix) {
525				keep = true
526			}
527			if strings.HasPrefix(line, "$ ") {
528				keep = true
529				keepNextResult = true
530			}
531			for _, kw := range []string{"error", "Error", "ERROR", "warning", "Warning", "WARN", "FAIL", "fail", "panic"} {
532				if strings.Contains(line, kw) {
533					keep = true
534					break
535				}
536			}
537			for _, kw := range []string{"hx-", "helix-", "FEAT-", "US-", "COMPLETE", "BLOCKED", "CLOSED", "closed", "commit "} {
538				if strings.Contains(line, kw) {
539					keep = true
540					break
541				}
542			}
543			if len(line) > 0 && condenseIsAlphaNumUnderscore(rune(line[0])) && strings.Contains(line, ":") {
544				keep = true
545			}
546			if strings.HasPrefix(line, "#") || strings.HasPrefix(line, "|") || strings.HasPrefix(line, " |") || strings.HasPrefix(line, "**") {
547				keep = true
548			}
549			if strings.HasPrefix(line, "Phase") || strings.HasPrefix(line, "Step") || strings.HasPrefix(line, "---") {
550				keep = true
551			}
552			if keep {
553				if lastWasKept && blankRun > 0 {
554					kept = append(kept, "")
555				}
556				blankRun = 0
557				lastWasKept = true
558				kept = append(kept, line)
559			}
560		}
561	
562		if len(kept) == 0 {
563			return ""
564		}
565		result := strings.Join(kept, "\n")
566		return condenseTrimBlankLines(result)
567	}
