569	func condenseIsDiffHeader(line string) bool {
570		return strings.HasPrefix(line, "diff --git ") ||
571			strings.HasPrefix(line, "index ") ||
572			strings.HasPrefix(line, "--- a/") ||
573			strings.HasPrefix(line, "+++ b/") ||
574			strings.HasPrefix(line, "@@ ")
575	}
576	
577	func condenseIsAlphaNumUnderscore(r rune) bool {
578		return (r >= 'A' && r <= 'Z') || (r >= '0' && r <= '9') || r == '_'
579	}
