581	func condenseTrimBlankLines(s string) string {
582		lines := strings.Split(s, "\n")
583		start := 0
584		for start < len(lines) && strings.TrimSpace(lines[start]) == "" {
585			start++
586		}
587		end := len(lines)
588		for end > start && strings.TrimSpace(lines[end-1]) == "" {
589			end--
590		}
591		return strings.Join(lines[start:end], "\n")
592	}
