672	func benchSummarize(result *BenchmarkResult) BenchmarkSummary {
673		summary := BenchmarkSummary{
674			TotalPrompts: len(result.Comparisons),
675		}
676		armStats := make(map[string]*BenchmarkArmSummary)
677		armOrder := make([]string, len(result.Arms))
678		for i, arm := range result.Arms {
679			label := arm.Label
680			armOrder[i] = label
681			armStats[label] = &BenchmarkArmSummary{Label: label}
682		}
683		for _, cmp := range result.Comparisons {
684			for _, arm := range cmp.Arms {
685				stats, ok := armStats[arm.Harness]
686				if !ok {
687					continue
688				}
689				if arm.ExitCode == 0 {
690					stats.Completed++
691				} else {
692					stats.Failed++
693				}
694				stats.TotalTokens += arm.Tokens
695				stats.TotalCostUSD += arm.CostUSD
696				stats.AvgDurationMS += arm.DurationMS
697			}
698		}
699		for _, label := range armOrder {
700			stats := armStats[label]
701			total := stats.Completed + stats.Failed
702			if total > 0 {
703				stats.AvgDurationMS = stats.AvgDurationMS / total
704			}
705			summary.Arms = append(summary.Arms, *stats)
706		}
707		return summary
708	}
